(1, 5, 'Halfmoon Lavender Gold', 'halfmoon-lavender-gold', 'A refined premium halfmoon with elegant color layering and balanced finnage.', 'This premium halfmoon betta features a lavender-gold presentation with strong form, elegant spread, and collector-grade visual appeal.', 'Betta splendens', 'Halfmoon', 'Premium', 280.00, 'USD', 'Thailand', 'Bangkok', 'hidden', 'fixed', 1, 25.00, 5.00, NULL, NULL, NULL, NULL, 60.00, '2026-04-05 15:53:21', '2026-04-07 15:53:21', 'cancelled', NULL, NULL, NULL, 0, NULL, NULL, 'available', 1, 0, 1, NULL, NULL, NULL, 0, '/uploads/listings/1/listing-1-20260319145600-119ad740c490d0de.webp', 'Halfmoon Lavender Gold | Bettavaro', 'Discover the Halfmoon Lavender Gold listing on Bettavaro.', NULL, NULL, '2026-03-19 13:50:35', '2026-04-12 14:14:51'),
(2, NULL, 'Rosetail', 'copper-galaxy-rosetail', 'A striking rosetail with metallic body depth and luminous copper tone.', 'Copper Galaxy Rosetail presents a dramatic metallic body, flowing finnage, and collector-focused visual elegance.', 'Betta splendens', 'Rosetail', 'Elite', 280.00, 'USD', 'Thailand', 'Chiang Mai', 'hidden', 'fixed', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, 'available', 1, 0, 1, NULL, NULL, NULL, 0, '/uploads/listings/2/002-20260325-070307-7f1a52d13685.webp', 'Copper Galaxy Rosetail | Bettavaro', 'Explore the Copper Galaxy Rosetail listing on Bettavaro.', NULL, NULL, '2026-03-19 13:50:35', '2026-04-03 00:18:31'),
(3, NULL, 'Black Samurai Show Grade', 'black-samurai-show-grade', 'A bold, high-contrast fish prepared for serious collectors.', 'Black Samurai Show Grade offers a powerful contrast pattern, premium structure, and a presentation tailored to the upper end of the market.', 'Betta splendens', 'Plakat', 'Show Grade', 80.00, 'USD', 'Indonesia', 'Jakarta', 'hidden', 'fixed', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, NULL, 'available', 1, 0, 1, NULL, NULL, NULL, 0, '/uploads/listings/3/listing-3-20260319145329-364f70c960afb8ee.jpg', 'Black Samurai Show Grade | Bettavaro', 'View the Black Samurai Show Grade listing on Bettavaro.', NULL, NULL, '2026-03-19 13:50:35', '2026-04-11 18:08:57'),
